    const personalizedStakes = todayEmail.stakesHtml.replace(/\{\{first_name\}\}/g, firstName).replace(/\{\{city\}\}/g, city);
    bodyContentHtml = bodySection(personalizedStakes) + urgencyCountdown(todayEmail.urgencyLabel, todayEmail.urgencyDisplay) + benefitsBox(todayEmail.benefitsHtml);
  } else {
    const personalizedHeadline = todayEmail.headline.replace(/\{\{city\}\}/g, city).replace(/\{\{first_name\}\}/g, firstName);
    const personalizedSubheadline = todayEmail.subheadline.replace(/\{\{city\}\}/g, city).replace(/\{\{first_name\}\}/g, firstName);
