    const personalizedBody = todayEmail.bodyHtml.replace(/\{\{first_name\}\}/g, firstName).replace(/\{\{city\}\}/g, city);
    bodyContentHtml = bodySection(personalizedBody);
  }

  const previewText = todayEmail.previewText.replace(/\{\{city\}\}/g, city).replace(/\{\{first_name\}\}/g, firstName);
  const ctaText = todayEmail.ctaText.replace(/\{\{first_name\}\}/g, firstName).replace(/\{\{city\}\}/g, city);

